var input = inputs.Length > 0 && inputs[0] != null ? inputs[0]! : new PixelBuffer(context.TileSize, context.TileSize);
var threshold = GetFloat(parameters, "threshold", 0.5f);
var softness = Math.Max(0.001f, GetFloat(parameters, "softness", 0.1f));
var mode = GetChoice(parameters, "mode", "blackWhite");
var lower = GetFloat(parameters, "lower", 0.3f);
var upper = GetFloat(parameters, "upper", 0.7f);
var fgColor = GetColor(parameters, "fgColor", Colors.White);
var bgColor = GetColor(parameters, "bgColor", Colors.Black);
var channel = GetChoice(parameters, "channel", "luminance");
var invert = GetBool(parameters, "invert", false);

var size = context.TileSize;
var buffer = new PixelBuffer(size, size);

var fgR = fgColor.R / 255f; var fgG = fgColor.G / 255f; var fgB = fgColor.B / 255f;
var bgR = bgColor.R / 255f; var bgG = bgColor.G / 255f; var bgB = bgColor.B / 255f;

buffer.ParallelForEachPixel((x, y) =>
{
    var (r, g, b, a) = input.GetPixel(x, y);

    // Extract channel value
    var val = channel switch
    {
        "R" => r,
        "G" => g,
        "B" => b,
        "A" => a,
        _ => r * 0.299f + g * 0.587f + b * 0.114f  // luminance
    };

    float t;
    if (mode == "bandPass")
    {
        // Band-pass: smoothstep between lower and upper
        var tLow = (val - lower + softness * 0.5f) / softness;
        var tHigh = (upper - val + softness * 0.5f) / softness;
        t = Math.Clamp(tLow, 0f, 1f) * Math.Clamp(tHigh, 0f, 1f);
    }
    else
    {
        t = (val - threshold + softness * 0.5f) / softness;
        t = Math.Clamp(t, 0f, 1f);
    }

    if (invert) t = 1f - t;

    if (mode == "blackWhite")
    {
        buffer.SetPixel(x, y,
            Lerp(bgR, fgR, t),
            Lerp(bgG, fgG, t),
            Lerp(bgB, fgB, t), 1f);
    }
    else
    {
        // preserveColor: blend between original and foreground based on threshold
        buffer.SetPixel(x, y,
            Lerp(r, fgR, t),
            Lerp(g, fgG, t),
            Lerp(b, fgB, t), a);
    }
});

return buffer;
}
